  ('bookkeeper-moex-01419', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國記帳士法之規定，下列敘述何者錯誤？', '["記帳士因業務之犯罪行為經判刑確定者，應付懲戒", "違反記帳士公會章程之規定，情節重大者，應付懲戒", "記帳士受申誡處分三次以上者，應另受停止執行業務之處分", "記帳士受停止執行業務處分累計滿三年者，應予除名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01420', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國記帳士法之規定，下列敘述何者正確？', '["記帳士登錄後，可以申請不加入記帳士公會，自行執業", "記帳士公會得拒絕具有會員資格者加入", "記帳士因懈怠或疏忽，致委任人或其利害關係人受有損害時，應負賠償責任", "記帳士受委任後，非有正當事由，不得終止其契約。如須終止契約，應於30日前通知委任人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01421', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國記帳士法之規定，下列何者不是記帳士在其登錄區域內可執行之業務？', '["受委任代訴願人提起訴願", "受委任辦理各項稅捐稽徵案件之申報及申請事項", "受委任辦理營業、變更、註銷、停業、復業及其他登記事項", "受理稅務諮詢事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01422', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '同級記帳士公會理事長若連任，依記帳士法第23條規定其可連續擔任理事長一職最長為幾年？', '["四年", "六年", "八年", "十年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
